const express = require('express');
const helmet = require('helmet');

const app = express();
const PORT = process.env.PORT || 3000;

// ---------------------------------------------------------------------------
// Security middleware
// ---------------------------------------------------------------------------

// helmet sets secure HTTP headers (X-Content-Type-Options, CSP, HSTS, etc.)
// and removes the X-Powered-By header that leaks framework info.
app.use(helmet());

// Parse JSON bodies with a strict size limit to prevent large-payload DoS.
app.use(express.json({ limit: '1mb' }));

// Disable ETag fingerprinting (optional – depends on caching strategy).
app.disable('x-powered-by');

// ---------------------------------------------------------------------------
// Routes
// ---------------------------------------------------------------------------

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate optional query parameters before use
  const allowedParams = ['id', 'name', 'limit', 'offset'];
  const unknownParams = Object.keys(req.query).filter(
    (key) => !allowedParams.includes(key)
  );

  if (unknownParams.length > 0) {
    return res.status(400).json({
      error: 'Bad Request',
      message: `Unknown query parameter(s): ${unknownParams.join(', ')}`,
    });
  }

  // Example: validate 'limit' and 'offset' if provided
  if (req.query.limit !== undefined) {
    const limit = Number(req.query.limit);
    if (!Number.isInteger(limit) || limit < 1 || limit > 100) {
      return res.status(400).json({
        error: 'Bad Request',
        message: 'limit must be an integer between 1 and 100',
      });
    }
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  res.json(users);
});

// ---------------------------------------------------------------------------
// 404 handler – catch requests to undefined routes
// ---------------------------------------------------------------------------
app.use((_req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// ---------------------------------------------------------------------------
// Global error handler – must have 4 parameters so Express recognises it
// ---------------------------------------------------------------------------
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  // Log the full error server-side for debugging
  console.error('Unhandled error:', err);

  // Never expose stack traces or internal details to the client
  res.status(err.status || 500).json({
    error: 'Internal Server Error',
  });
});

// ---------------------------------------------------------------------------
// Start server
// ---------------------------------------------------------------------------
if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

module.exports = app;

