Here's what the improved version would look like:

```js
const express = require('express');
const helmet = require('helmet');       // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting
const cors = require('cors');           // CORS configuration

const app = express();

// --- Security Middleware ---

// Set security-related HTTP headers (removes X-Powered-By, adds CSP, HSTS, etc.)
app.use(helmet());

// Configure CORS explicitly — restrict to known origins in production
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || 'http://localhost:3000',
  methods: ['GET'],
}));

// Rate limiting to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Body parsing with size limits (for future POST/PUT routes)
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Example: validate query params if filtering is added later
  const { id } = req.query;
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  if (id !== undefined) {
    const numericId = Number(id);
    if (!Number.isInteger(numericId) || numericId < 1) {
      return res.status(400).json({ error: 'Invalid user ID. Must be a positive integer.' });
    }
    const user = users.find((u) => u.id === numericId);
    if (!user) {
      return res.status(404).json({ error: 'User not found.' });
    }
    return res.json(user);
  }

  res.json(users);
});

