  // TODO: add authentication middleware before production
  const users = [
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ];
  res.json(users); // emails stripped from public response
});

// --- Error handling ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({ error: 'Internal Server Error' });
});

// --- Server ---
const PORT = process.env.PORT || 3000;
const HOST = process.env.HOST || '127.0.0.1';

app.listen(PORT, HOST, () => {
  console.log(`Server running on ${HOST}:${PORT}`);
});

module.exports = app;
```

---

**Bottom line:** The app is currently a skeleton, but it's missing every layer of defense-in-depth. The most urgent fixes are: **add helmet** (1 line), **remove emails from the public `/users` response**, and **add rate limiting**. These three changes address the most exploitable issues with minimal effort. Authentication should be the next priority before any deployment.

